async (page) => {
  var title = "图解 Blaze · 第 23 章 · 高级查询与自定义函数 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 23 章 · 高级查询与自定义函数</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">动态条件 · 聚合仪表盘 · 窗口函数 · CTE 排名 · 递归分类树 · JpqlFunction · JpqlMacro · View 继承 · 关联子查询</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\"><span style=\"color:#1e6fff;\">第 22 章</span> 完成了 Spring Boot + Blaze-Persistence 的基础 CRUD 搭建——实体定义、Entity View 投影、分页列表和增删改接口一应俱全。但真实的电商系统远不止\"增删改查\"：运营团队需要<strong style=\"color:#1a1a2e;font-weight:700;\">动态筛选订单</strong>，产品经理需要<strong style=\"color:#1a1a2e;font-weight:700;\">仪表盘统计</strong>，市场团队需要<strong style=\"color:#1a1a2e;font-weight:700;\">客户消费排名</strong>，目录管理需要<strong style=\"color:#1a1a2e;font-weight:700;\">递归分类树</strong>，搜索功能需要<strong style=\"color:#1a1a2e;font-weight:700;\">PostgreSQL 全文检索</strong>。本章将一一攻破这些高级查询场景，并深入 Blaze-Persistence 的两大扩展机制——<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlMacro</code>。</p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">动态查询：Specification 动态条件 · <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 聚合仪表盘 · Correlated Subquery 关联统计</li><li style=\"margin-bottom:4px;font-size:13px;\">分析计算：窗口函数排名 · CTE Top N 报表 · 递归 CTE 分类树</li><li style=\"margin-bottom:4px;font-size:13px;\">扩展机制：JpqlFunction 全文搜索 · JpqlMacro 审计注入 · 多态 View 继承 · 陷阱规避</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 22 章</span> 的 Spring Boot 项目结构，<span style=\"color:#1e6fff;\">第 3 章</span> CriteriaBuilder 基础，<span style=\"color:#1e6fff;\">第 4 章</span> Entity View 投影，<span style=\"color:#1e6fff;\">第 8 章</span> CTE，<span style=\"color:#1e6fff;\">第 9 章</span> 窗口函数，<span style=\"color:#1e6fff;\">第 20 章</span> 扩展体系。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-1 本章高级查询技术全景图</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n① 动态查询\nSpecification — JPA 标准方式<br/>CriteriaBuilder — Blaze 流式 API\n\n\n② 聚合 & 窗口\n聚合 Entity View — COUNT / SUM / AVG<br/>窗口函数 — RANK / 趋势\n\n\n③ CTE\n普通 CTE — 月度排名 Top N<br/>递归 CTE — 分类树展开\n\n\n④ 扩展机制\nJpqlFunction — PG 全文搜索<br/>JpqlMacro — 审计字段注入\n\n\n⑤ 高级 View\n继承 & 多态 — 按状态分派 View<br/>Correlated Subquery — 关联计算字段\n\n</p></section>\n<section style=\"margin:12px 0 20px;\"><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">10</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">高级查询模式</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">2</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">扩展机制</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">1 SQL</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">复杂报表</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">∞</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">递归深度</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.1 动态条件查询 — EntityViewSpecificationExecutor</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">电商后台最常见的需求——运营人员在订单管理页面输入多种筛选条件（状态、客户、金额范围、日期区间），后端需要<strong style=\"color:#1a1a2e;font-weight:700;\">动态拼接</strong>查询条件。Blaze-Persistence 提供两种方式：JPA <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Specification</code> 整合和原生 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code> 流式拼接。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">搜索请求 DTO</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public record OrderSearchRequest(<br/>    OrderStatus status,<br/>    Long customerId,<br/>    BigDecimal minAmount,<br/>    BigDecimal maxAmount,<br/>    LocalDateTime dateFrom,<br/>    LocalDateTime dateTo,<br/>    String keyword<br/>) {}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">方式一：Specification + EntityViewSpecificationExecutor</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Spring Data 集成模块提供了 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewSpecificationExecutor</code> 接口，让 Repository 直接接受 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Specification</code> 参数并返回 Entity View 投影结果。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public interface OrderRepository<br/>        extends EntityViewRepository&lt;OrderListView, Long&gt;,<br/>                EntityViewSpecificationExecutor&lt;OrderListView, Order&gt; {<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Service<br/>@RequiredArgsConstructor<br/>public class OrderSearchService {<br/><br/>    private final OrderRepository orderRepo;<br/><br/>    public Page&lt;OrderListView&gt; searchOrders(OrderSearchRequest req,<br/>                                             Pageable pageable) {<br/>        return orderRepo.findAll(<br/>            (root, query, cb) -&gt; {<br/>                var predicates = new ArrayList&lt;Predicate&gt;();<br/><br/>                if (req.status() != null)<br/>                    predicates.add(<br/>                        cb.equal(root.get(\"status\"), req.status()));<br/><br/>                if (req.customerId() != null)<br/>                    predicates.add(<br/>                        cb.equal(root.get(\"customer\").get(\"id\"),<br/>                                 req.customerId()));<br/><br/>                if (req.minAmount() != null)<br/>                    predicates.add(<br/>                        cb.greaterThanOrEqualTo(<br/>                            root.get(\"totalAmount\"), req.minAmount()));<br/><br/>                if (req.maxAmount() != null)<br/>                    predicates.add(<br/>                        cb.lessThanOrEqualTo(<br/>                            root.get(\"totalAmount\"), req.maxAmount()));<br/><br/>                if (req.dateFrom() != null)<br/>                    predicates.add(<br/>                        cb.greaterThanOrEqualTo(<br/>                            root.get(\"createdAt\"), req.dateFrom()));<br/><br/>                if (req.dateTo() != null)<br/>                    predicates.add(<br/>                        cb.lessThanOrEqualTo(<br/>                            root.get(\"createdAt\"), req.dateTo()));<br/><br/>                return cb.and(predicates.toArray(new Predicate[0]));<br/>            },<br/>            pageable<br/>        );<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 当 status=PAID, minAmount=100, dateFrom=2026-01-01 时生成的 SQL:<br/>SELECT o.id, o.status, o.total_amount, c.name AS customer_name,<br/>       o.created_at<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>WHERE o.status = 'PAID'<br/>  AND o.total_amount &gt;= 100<br/>  AND o.created_at &gt;= '2026-01-01'<br/>ORDER BY o.created_at DESC<br/>LIMIT 20 OFFSET 0</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-2 动态条件查询请求处理流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">前端筛选面板</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">OrderController</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">OrderSearchService</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">OrderRepository</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">PostgreSQL</th></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">方式二：CriteriaBuilder 流式拼接</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">对于需要更细粒度控制的场景（如动态排序、跨表联合条件），直接用 Blaze-Persistence 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code> 提供更大灵活性。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Service<br/>@RequiredArgsConstructor<br/>public class OrderCriteriaSearchService {<br/><br/>    private final CriteriaBuilderFactory cbf;<br/>    private final EntityViewManager evm;<br/>    private final EntityManager em;<br/><br/>    public List&lt;OrderListView&gt; searchWithCriteria(OrderSearchRequest req) {<br/>        CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class, \"o\");<br/><br/>        if (req.status() != null)<br/>            cb.where(\"o.status\").eq(req.status());<br/><br/>        if (req.customerId() != null)<br/>            cb.where(\"o.customer.id\").eq(req.customerId());<br/><br/>        if (req.minAmount() != null)<br/>            cb.where(\"o.totalAmount\").ge(req.minAmount());<br/><br/>        if (req.maxAmount() != null)<br/>            cb.where(\"o.totalAmount\").le(req.maxAmount());<br/><br/>        if (req.dateFrom() != null)<br/>            cb.where(\"o.createdAt\").ge(req.dateFrom());<br/><br/>        if (req.dateTo() != null)<br/>            cb.where(\"o.createdAt\").le(req.dateTo());<br/><br/>        if (req.keyword() != null &amp;&amp; !req.keyword().isBlank())<br/>            cb.where(\"o.customer.name\").like()<br/>              .value(\"%\" + req.keyword() + \"%\").noEscape();<br/><br/>        return evm.applySetting(<br/>            EntityViewSetting.create(OrderListView.class),<br/>            cb<br/>        ).getResultList();<br/>    }<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-3 Specification vs CriteriaBuilder 对比决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Blaze</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Persistence</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">需要动态查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要 Spring Data<br/>分页/排序集成？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ Specification<br/>EntityViewSpecificationExecutor</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要 CTE / 窗口函数<br/>/ 高级表达式？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ CriteriaBuilder<br/>Blaze-Persistence 原生</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 团队熟悉 JPA Criteria？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回 Page<View><br/>自动 COUNT 查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">返回 List<View><br/>手动处理分页</p></section></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">维度</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Specification</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">CriteriaBuilder</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">分页集成</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">原生支持 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Pageable</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">需手动 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.page()</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">表达式能力</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">标准 JPA Criteria</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">CTE / 窗口函数 / MULTISET</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">类型安全</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Metamodel 可选</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">字符串表达式</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">学习曲线</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">JPA 生态通用</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Blaze-Persistence 特有</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">组合性</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Specification.and/or</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">链式 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.where()</code></td></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.2 聚合统计 — 仪表盘</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">产品经理需要一个运营仪表盘：按月统计订单数量、总收入、平均客单价、去重客户数。传统做法需要写原生 SQL 或复杂 JPQL；用 Entity View 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 聚合表达式，可以在编译期就定义好所有聚合逻辑。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">聚合 Entity View 定义</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface MonthlySalesView {<br/><br/>    @Mapping(\"FUNCTION('EXTRACT_MONTH', createdAt)\")<br/>    Integer getMonth();<br/><br/>    @Mapping(\"FUNCTION('EXTRACT_YEAR', createdAt)\")<br/>    Integer getYear();<br/><br/>    @Mapping(\"COUNT(id)\")<br/>    Long getOrderCount();<br/><br/>    @Mapping(\"SUM(totalAmount)\")<br/>    BigDecimal getTotalRevenue();<br/><br/>    @Mapping(\"AVG(totalAmount)\")<br/>    BigDecimal getAvgOrderValue();<br/><br/>    @Mapping(\"COUNT(DISTINCT customer.id)\")<br/>    Long getUniqueCustomers();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Repository<br/>public interface SalesReportRepository<br/>        extends EntityViewRepository&lt;MonthlySalesView, Long&gt; {<br/>}<br/><br/>@Service<br/>@RequiredArgsConstructor<br/>public class DashboardService {<br/><br/>    private final CriteriaBuilderFactory cbf;<br/>    private final EntityViewManager evm;<br/>    private final EntityManager em;<br/><br/>    public List&lt;MonthlySalesView&gt; getMonthlySales(int year) {<br/>        CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class, \"o\")<br/>            .where(\"o.status\").notEq(OrderStatus.CANCELLED)<br/>            .where(\"FUNCTION('EXTRACT_YEAR', o.createdAt)\").eq(year);<br/><br/>        return evm.applySetting(<br/>            EntityViewSetting.create(MonthlySalesView.class),<br/>            cb<br/>        ).getResultList();<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>SELECT EXTRACT(MONTH FROM o.created_at) AS month,<br/>       EXTRACT(YEAR FROM o.created_at) AS year,<br/>       COUNT(o.id) AS order_count,<br/>       SUM(o.total_amount) AS total_revenue,<br/>       AVG(o.total_amount) AS avg_order_value,<br/>       COUNT(DISTINCT o.customer_id) AS unique_customers<br/>FROM orders o<br/>WHERE o.status &lt;&gt; 'CANCELLED'<br/>  AND EXTRACT(YEAR FROM o.created_at) = 2026<br/>GROUP BY EXTRACT(MONTH FROM o.created_at),<br/>         EXTRACT(YEAR FROM o.created_at)<br/>ORDER BY EXTRACT(MONTH FROM o.created_at) ASC</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-4 聚合 Entity View 从订单表到仪表盘的数据流</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">RAW</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">id=1, amount=299, customer=A, 2026-01</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">id=2, amount=150, customer=B, 2026-01</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">id=3, amount=499, customer=A, 2026-02</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">...</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">AGG</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">EXTRACT(MONTH)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">COUNT(id)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SUM(totalAmount)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">AVG(totalAmount)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">COUNT(DISTINCT customer)</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">RESULT</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">1月: 1200单, ¥358K, ¥298, 890人</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">2月: 980单, ¥290K, ¥296, 720人</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">3月: 1450单, ¥420K, ¥290, 1050人</p></section></td></tr></table></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Tuple 方式——更灵活的聚合查询</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;Tuple&gt; getMonthlySalesTuples(int year) {<br/>    CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>        .from(Order.class, \"o\")<br/>        .select(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\", \"month\")<br/>        .select(\"COUNT(o.id)\", \"orderCount\")<br/>        .select(\"SUM(o.totalAmount)\", \"totalRevenue\")<br/>        .select(\"AVG(o.totalAmount)\", \"avgOrderValue\")<br/>        .select(\"COUNT(DISTINCT o.customer.id)\", \"uniqueCustomers\")<br/>        .where(\"o.status\").notEq(OrderStatus.CANCELLED)<br/>        .where(\"FUNCTION('EXTRACT_YEAR', o.createdAt)\").eq(year)<br/>        .groupBy(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\")<br/>        .orderByAsc(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\");<br/><br/>    return cb.getResultList();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">Entity View vs Tuple 聚合的选择</strong>：如果聚合字段是固定的（仪表盘），优先用 Entity View——类型安全、接口稳定、可测试。如果聚合字段需要动态变化（用户自选指标），用 Tuple 更灵活。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">多维度聚合——按状态 + 月份交叉统计</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface StatusMonthlySalesView {<br/><br/>    @Mapping(\"status\")<br/>    OrderStatus getStatus();<br/><br/>    @Mapping(\"FUNCTION('EXTRACT_MONTH', createdAt)\")<br/>    Integer getMonth();<br/><br/>    @Mapping(\"COUNT(id)\")<br/>    Long getOrderCount();<br/><br/>    @Mapping(\"SUM(totalAmount)\")<br/>    BigDecimal getTotalRevenue();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 交叉统计 SQL:<br/>SELECT o.status,<br/>       EXTRACT(MONTH FROM o.created_at) AS month,<br/>       COUNT(o.id),<br/>       SUM(o.total_amount)<br/>FROM orders o<br/>WHERE EXTRACT(YEAR FROM o.created_at) = 2026<br/>GROUP BY o.status, EXTRACT(MONTH FROM o.created_at)<br/>ORDER BY o.status, EXTRACT(MONTH FROM o.created_at)</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.3 窗口函数 — 排名与趋势</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">窗口函数是 SQL 分析的杀手级特性——在不改变行数的前提下，为每行计算排名、累计和、移动平均等聚合值。Blaze-Persistence 在 JPQL 层面提供了完整的窗口函数支持。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">客户消费排名</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;Tuple&gt; getCustomerSpendingRank() {<br/>    CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>        .from(Order.class, \"o\")<br/>        .select(\"o.customer.id\", \"customerId\")<br/>        .select(\"o.customer.name\", \"customerName\")<br/>        .select(\"SUM(o.totalAmount)\", \"totalSpent\")<br/>        .select(\"COUNT(o.id)\", \"orderCount\")<br/>        .select(\"WINDOW_RANK() OVER (\"<br/>              + \"ORDER BY SUM(o.totalAmount) DESC)\", \"spendingRank\")<br/>        .select(\"WINDOW_DENSE_RANK() OVER (\"<br/>              + \"ORDER BY SUM(o.totalAmount) DESC)\", \"denseRank\")<br/>        .where(\"o.status\").eq(OrderStatus.COMPLETED)<br/>        .groupBy(\"o.customer.id\")<br/>        .groupBy(\"o.customer.name\")<br/>        .orderByAsc(\"WINDOW_RANK() OVER (\"<br/>                  + \"ORDER BY SUM(o.totalAmount) DESC)\");<br/><br/>    return cb.getResultList();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>SELECT o.customer_id,<br/>       c.name,<br/>       SUM(o.total_amount) AS total_spent,<br/>       COUNT(o.id) AS order_count,<br/>       RANK() OVER (ORDER BY SUM(o.total_amount) DESC) AS spending_rank,<br/>       DENSE_RANK() OVER (ORDER BY SUM(o.total_amount) DESC) AS dense_rank<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>WHERE o.status = 'COMPLETED'<br/>GROUP BY o.customer_id, c.name<br/>ORDER BY spending_rank</p></section>\n\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">月度销售趋势——累计与环比</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;Tuple&gt; getMonthlySalesTrend(int year) {<br/>    CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>        .from(Order.class, \"o\")<br/>        .select(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\", \"month\")<br/>        .select(\"SUM(o.totalAmount)\", \"monthlyRevenue\")<br/>        .select(\"WINDOW_SUM(SUM(o.totalAmount)) OVER (\"<br/>              + \"ORDER BY FUNCTION('EXTRACT_MONTH', o.createdAt) \"<br/>              + \"ROWS UNBOUNDED PRECEDING)\", \"cumulativeRevenue\")<br/>        .select(\"WINDOW_LAG(SUM(o.totalAmount), 1) OVER (\"<br/>              + \"ORDER BY FUNCTION('EXTRACT_MONTH', o.createdAt))\",<br/>              \"prevMonthRevenue\")<br/>        .where(\"o.status\").notEq(OrderStatus.CANCELLED)<br/>        .where(\"FUNCTION('EXTRACT_YEAR', o.createdAt)\").eq(year)<br/>        .groupBy(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\")<br/>        .orderByAsc(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\");<br/><br/>    return cb.getResultList();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（一条语句同时返回月度、累计、环比）:<br/>SELECT EXTRACT(MONTH FROM o.created_at) AS month,<br/>       SUM(o.total_amount) AS monthly_revenue,<br/>       SUM(SUM(o.total_amount)) OVER (<br/>           ORDER BY EXTRACT(MONTH FROM o.created_at)<br/>           ROWS UNBOUNDED PRECEDING<br/>       ) AS cumulative_revenue,<br/>       LAG(SUM(o.total_amount), 1) OVER (<br/>           ORDER BY EXTRACT(MONTH FROM o.created_at)<br/>       ) AS prev_month_revenue<br/>FROM orders o<br/>WHERE o.status &lt;&gt; 'CANCELLED'<br/>  AND EXTRACT(YEAR FROM o.created_at) = 2026<br/>GROUP BY EXTRACT(MONTH FROM o.created_at)<br/>ORDER BY month</p></section>\n\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">月份</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">月度收入</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">累计收入</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">上月收入</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">环比增长</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1月</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥300K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥300K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">—</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">—</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2月</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥280K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥580K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥300K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">-6.7%</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">3月</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥350K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥930K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥280K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">+25%</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">4月</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥420K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥1,350K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">¥350K</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">+20%</td></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.4 CTE — 月度销售排名报表</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">CTE（公用表表达式）将复杂查询分解为命名步骤。在报表场景中，先用 CTE 计算每位客户的月度消费总额和排名，再从 CTE 结果中筛选 Top 10——比嵌套子查询可读性高一个量级。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CTE 实体定义</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@CTE<br/>@Entity<br/>public class MonthlySalesCTE {<br/>    @Id Long customerId;<br/>    String customerName;<br/>    Integer salesMonth;<br/>    BigDecimal monthlyTotal;<br/>    Long orderCount;<br/>    Integer salesRank;<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">CTE 实体必须满足三个条件</strong>：① 标注 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@CTE</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Entity</code>；② 必须有 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Id</code> 字段；③ 必须在 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">persistence.xml</code> 或 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityScan</code> 中注册。缺少任何一项都会导致运行时异常。\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Service<br/>@RequiredArgsConstructor<br/>public class SalesRankingService {<br/><br/>    private final CriteriaBuilderFactory cbf;<br/>    private final EntityManager em;<br/><br/>    public List&lt;Tuple&gt; getTopCustomersByMonth(int year, int month,<br/>                                               int topN) {<br/>        CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>            .with(MonthlySalesCTE.class)<br/>                .from(Order.class, \"o\")<br/>                .bind(\"customerId\").select(\"o.customer.id\")<br/>                .bind(\"customerName\").select(\"o.customer.name\")<br/>                .bind(\"salesMonth\")<br/>                    .select(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\")<br/>                .bind(\"monthlyTotal\").select(\"SUM(o.totalAmount)\")<br/>                .bind(\"orderCount\").select(\"COUNT(o.id)\")<br/>                .bind(\"salesRank\")<br/>                    .select(\"WINDOW_RANK() OVER (\"<br/>                          + \"PARTITION BY \"<br/>                          + \"FUNCTION('EXTRACT_MONTH', o.createdAt) \"<br/>                          + \"ORDER BY SUM(o.totalAmount) DESC)\")<br/>                .where(\"o.status\").eq(OrderStatus.COMPLETED)<br/>                .where(\"FUNCTION('EXTRACT_YEAR', o.createdAt)\").eq(year)<br/>                .groupBy(\"o.customer.id\")<br/>                .groupBy(\"o.customer.name\")<br/>                .groupBy(\"FUNCTION('EXTRACT_MONTH', o.createdAt)\")<br/>            .end()<br/>            .from(MonthlySalesCTE.class, \"c\")<br/>            .select(\"c.customerName\")<br/>            .select(\"c.salesMonth\")<br/>            .select(\"c.monthlyTotal\")<br/>            .select(\"c.orderCount\")<br/>            .select(\"c.salesRank\")<br/>            .where(\"c.salesMonth\").eq(month)<br/>            .where(\"c.salesRank\").le(topN)<br/>            .orderByAsc(\"c.salesRank\");<br/><br/>        return cb.getResultList();<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>WITH MonthlySalesCTE(customer_id, customer_name, sales_month,<br/>                     monthly_total, order_count, sales_rank) AS (<br/>    SELECT o.customer_id,<br/>           c.name,<br/>           EXTRACT(MONTH FROM o.created_at),<br/>           SUM(o.total_amount),<br/>           COUNT(o.id),<br/>           RANK() OVER (<br/>               PARTITION BY EXTRACT(MONTH FROM o.created_at)<br/>               ORDER BY SUM(o.total_amount) DESC<br/>           )<br/>    FROM orders o<br/>    JOIN customers c ON o.customer_id = c.id<br/>    WHERE o.status = 'COMPLETED'<br/>      AND EXTRACT(YEAR FROM o.created_at) = 2026<br/>    GROUP BY o.customer_id, c.name,<br/>             EXTRACT(MONTH FROM o.created_at)<br/>)<br/>SELECT c.customer_name, c.sales_month,<br/>       c.monthly_total, c.order_count, c.sales_rank<br/>FROM MonthlySalesCTE c<br/>WHERE c.sales_month = 3<br/>  AND c.sales_rank &lt;= 10<br/>ORDER BY c.sales_rank</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-7 CTE 月度排名报表——两阶段执行流程</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">PHASE1</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">FROM orders o<br/>JOIN customers c</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">GROUP BY customer, month</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SUM(totalAmount)<br/>COUNT(id)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">RANK() OVER<br/>PARTITION BY month</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ MonthlySalesCTE<br/>(中间结果集)</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">PHASE2</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">FROM MonthlySalesCTE c</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WHERE month = 3<br/>AND rank <= 10</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ORDER BY salesRank</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ Top 10 客户列表</p></section></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">CTE vs 子查询</strong>：CTE 的优势不仅是可读性——PostgreSQL 12+ 的优化器会自动内联（inline）非递归 CTE，生成与子查询等价的执行计划。但递归 CTE 不会被内联，这是设计上的必然选择。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.5 递归 CTE — 分类树</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">电商系统的商品分类是典型的树形结构——\"电子产品 → 手机 → 智能手机 → 折叠屏手机\"可能有 4-6 层深度。用递归 CTE 可以在<strong style=\"color:#1a1a2e;font-weight:700;\">一条 SQL</strong> 中展开任意深度的分类树，无需应用层递归查询。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">分类实体</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Entity<br/>@Table(name = \"categories\")<br/>public class Category {<br/>    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)<br/>    private Long id;<br/><br/>    private String name;<br/><br/>    @ManyToOne(fetch = FetchType.LAZY)<br/>    @JoinColumn(name = \"parent_id\")<br/>    private Category parent;<br/><br/>    @OneToMany(mappedBy = \"parent\")<br/>    private List&lt;Category&gt; children;<br/><br/>    private Integer sortOrder;<br/>    private Boolean active;<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">递归 CTE 实体</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@CTE<br/>@Entity<br/>public class CategoryTreeCTE {<br/>    @Id Long id;<br/>    String name;<br/>    Long parentId;<br/>    Integer level;<br/>    String path;<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">递归 CTE 查询实现</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Service<br/>@RequiredArgsConstructor<br/>public class CategoryTreeService {<br/><br/>    private final CriteriaBuilderFactory cbf;<br/>    private final EntityManager em;<br/><br/>    public List&lt;Tuple&gt; getCategoryTree(Long rootId) {<br/>        CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>            .withRecursive(CategoryTreeCTE.class)<br/>                <span style=\"color:#6c7086;font-style:italic;\">// Anchor: 根节点</span><br/>                .from(Category.class, \"c\")<br/>                .bind(\"id\").select(\"c.id\")<br/>                .bind(\"name\").select(\"c.name\")<br/>                .bind(\"parentId\").select(\"c.parent.id\")<br/>                .bind(\"level\").select(\"0\")<br/>                .bind(\"path\").select(\"c.name\")<br/>                .where(\"c.id\").eq(rootId)<br/>            .unionAll()<br/>                <span style=\"color:#6c7086;font-style:italic;\">// Recursive: 子节点递归</span><br/>                .from(Category.class, \"child\")<br/>                .innerJoinOn(CategoryTreeCTE.class, \"parent\")<br/>                    .on(\"parent.id\").eqExpression(\"child.parent.id\")<br/>                .end()<br/>                .bind(\"id\").select(\"child.id\")<br/>                .bind(\"name\").select(\"child.name\")<br/>                .bind(\"parentId\").select(\"child.parent.id\")<br/>                .bind(\"level\").select(\"parent.level + 1\")<br/>                .bind(\"path\")<br/>                    .select(\"CONCAT(parent.path, ' → ', child.name)\")<br/>            .end()<br/>            .from(CategoryTreeCTE.class, \"t\")<br/>            .select(\"t.id\")<br/>            .select(\"t.name\")<br/>            .select(\"t.parentId\")<br/>            .select(\"t.level\")<br/>            .select(\"t.path\")<br/>            .orderByAsc(\"t.path\");<br/><br/>        return cb.getResultList();<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>WITH RECURSIVE CategoryTreeCTE(id, name, parent_id, level, path) AS (<br/>    -- Anchor: 根节点<br/>    SELECT c.id, c.name, c.parent_id, 0, CAST(c.name AS VARCHAR(1000))<br/>    FROM categories c<br/>    WHERE c.id = 1<br/><br/>    UNION ALL<br/><br/>    -- Recursive: 每层子节点<br/>    SELECT child.id, child.name, child.parent_id,<br/>           parent.level + 1,<br/>           CONCAT(parent.path, ' → ', child.name)<br/>    FROM categories child<br/>    INNER JOIN CategoryTreeCTE parent<br/>        ON parent.id = child.parent_id<br/>)<br/>SELECT t.id, t.name, t.parent_id, t.level, t.path<br/>FROM CategoryTreeCTE t<br/>ORDER BY t.path</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-8 递归 CTE 逐层展开分类树</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n🔹 Anchor — level=0\n电子产品 (id=1)\n\n→\n\n🔹 Iteration 1 — level=1\n手机 (id=2)<br/>电脑 (id=3) · 配件 (id=4)\n\n→\n\n🔹 Iteration 2 — level=2\n智能手机 (id=5) · 功能手机 (id=6)<br/>笔记本 (id=7) · 台式机 (id=8)\n\n→\n\n🔹 Iteration 3 — level=3\n折叠屏 (id=9)<br/>直板 (id=10)\n\n</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">id</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">name</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">level</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">path</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">电子产品</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">0</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">手机</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 手机</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">5</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">智能手机</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 手机 → 智能手机</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">9</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">折叠屏</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">3</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 手机 → 智能手机 → 折叠屏</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">10</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">直板</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">3</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 手机 → 智能手机 → 直板</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">6</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">功能手机</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 手机 → 功能手机</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">3</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">电脑</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 电脑</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">7</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">笔记本</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 电脑 → 笔记本</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">8</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">台式机</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 电脑 → 台式机</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">4</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">配件</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">电子产品 → 配件</code></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">带商品计数的分类树</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;Tuple&gt; getCategoryTreeWithProductCount(Long rootId) {<br/>    CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>        .withRecursive(CategoryTreeCTE.class)<br/>            .from(Category.class, \"c\")<br/>            .bind(\"id\").select(\"c.id\")<br/>            .bind(\"name\").select(\"c.name\")<br/>            .bind(\"parentId\").select(\"c.parent.id\")<br/>            .bind(\"level\").select(\"0\")<br/>            .bind(\"path\").select(\"c.name\")<br/>            .where(\"c.id\").eq(rootId)<br/>        .unionAll()<br/>            .from(Category.class, \"child\")<br/>            .innerJoinOn(CategoryTreeCTE.class, \"parent\")<br/>                .on(\"parent.id\").eqExpression(\"child.parent.id\")<br/>            .end()<br/>            .bind(\"id\").select(\"child.id\")<br/>            .bind(\"name\").select(\"child.name\")<br/>            .bind(\"parentId\").select(\"child.parent.id\")<br/>            .bind(\"level\").select(\"parent.level + 1\")<br/>            .bind(\"path\")<br/>                .select(\"CONCAT(parent.path, ' → ', child.name)\")<br/>        .end()<br/>        .from(CategoryTreeCTE.class, \"t\")<br/>        .leftJoinOn(Product.class, \"p\")<br/>            .on(\"p.category.id\").eqExpression(\"t.id\")<br/>        .end()<br/>        .select(\"t.id\")<br/>        .select(\"t.name\")<br/>        .select(\"t.level\")<br/>        .select(\"t.path\")<br/>        .select(\"COUNT(p.id)\", \"productCount\")<br/>        .groupBy(\"t.id\").groupBy(\"t.name\")<br/>        .groupBy(\"t.level\").groupBy(\"t.path\")<br/>        .orderByAsc(\"t.path\");<br/><br/>    return cb.getResultList();<br/>}</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.6 自定义 JpqlFunction — PostgreSQL 特有功能</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 扩展点允许在 JPQL 层面注册自定义函数，渲染时翻译为数据库原生语法。这是集成数据库特有功能（全文搜索、JSON 操作、数组函数）的标准方式。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-9 JpqlFunction 注册与渲染管线</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">APP</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JPQL: FUNCTION('pg_search',<br/>p.description, :keyword)</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">BP</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JpqlFunctionGroup<br/>查找 'pg_search'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">PgSearchFunction<br/>.render(ctx)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">ctx.addChunk(...)</p></section></td></tr></table></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">SQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">to_tsvector('chinese',<br/>p0_.description)<br/>@@ to_tsquery('chinese',<br/>?)</p></section></td></tr></table></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">PostgreSQL 全文搜索函数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class PgSearchFunction implements JpqlFunction {<br/><br/>    @Override<br/>    public boolean hasArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public boolean hasParenthesesIfNoArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public Class&lt;?&gt; getReturnType(Class&lt;?&gt; firstArgumentType) {<br/>        return Boolean.class;<br/>    }<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\"(to_tsvector('chinese', \");<br/>        ctx.addArgument(0);<br/>        ctx.addChunk(\") @@ to_tsquery('chinese', \");<br/>        ctx.addArgument(1);<br/>        ctx.addChunk(\"))\");<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">PostgreSQL 数组聚合函数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class ArrayAggFunction implements JpqlFunction {<br/><br/>    @Override<br/>    public boolean hasArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public boolean hasParenthesesIfNoArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public Class&lt;?&gt; getReturnType(Class&lt;?&gt; firstArgumentType) {<br/>        return String[].class;<br/>    }<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\"array_agg(DISTINCT \");<br/>        ctx.addArgument(0);<br/>        if (ctx.getArgumentsSize() &gt; 1) {<br/>            ctx.addChunk(\" ORDER BY \");<br/>            ctx.addArgument(1);<br/>        }<br/>        ctx.addChunk(\")\");<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">注册自定义函数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Configuration<br/>public class BlazePersistenceConfig {<br/><br/>    @Bean<br/>    @Scope(ConfigurableBeanFactory.SCOPE_SINGLETON)<br/>    public CriteriaBuilderFactory cbf(EntityManagerFactory emf) {<br/>        CriteriaBuilderConfiguration config = Criteria.getDefault();<br/><br/>        config.registerFunction(<br/>            new JpqlFunctionGroup(\"pg_search\",<br/>                                  new PgSearchFunction()));<br/>        config.registerFunction(<br/>            new JpqlFunctionGroup(\"array_agg\",<br/>                                  new ArrayAggFunction()));<br/>        config.registerFunction(<br/>            new JpqlFunctionGroup(\"pg_similarity\",<br/>                                  new PgSimilarityFunction()));<br/><br/>        return config.createCriteriaBuilderFactory(emf);<br/>    }<br/><br/>    @Bean<br/>    @Scope(ConfigurableBeanFactory.SCOPE_SINGLETON)<br/>    public EntityViewManager evm(CriteriaBuilderFactory cbf,<br/>                                  EntityViewConfiguration evc) {<br/>        return evc.createEntityViewManager(cbf);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">在查询中使用自定义函数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;Tuple&gt; fullTextSearch(String keyword) {<br/>    return cbf.create(em, Tuple.class)<br/>        .from(Product.class, \"p\")<br/>        .select(\"p.id\")<br/>        .select(\"p.name\")<br/>        .select(\"p.price\")<br/>        .select(\"p.category.name\", \"categoryName\")<br/>        .where(\"FUNCTION('pg_search', p.description, :keyword)\")<br/>            .eq(true)<br/>        .setParameter(\"keyword\", keyword)<br/>        .orderByDesc(\"p.price\")<br/>        .getResultList();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>SELECT p.id, p.name, p.price, c.name AS category_name<br/>FROM products p<br/>JOIN categories c ON p.category_id = c.id<br/>WHERE (to_tsvector('chinese', p.description)<br/>       @@ to_tsquery('chinese', ?))<br/>ORDER BY p.price DESC</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">模糊相似度搜索函数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class PgSimilarityFunction implements JpqlFunction {<br/><br/>    @Override<br/>    public boolean hasArguments() { return true; }<br/><br/>    @Override<br/>    public boolean hasParenthesesIfNoArguments() { return true; }<br/><br/>    @Override<br/>    public Class&lt;?&gt; getReturnType(Class&lt;?&gt; firstArgumentType) {<br/>        return Float.class;<br/>    }<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\"similarity(\");<br/>        ctx.addArgument(0);<br/>        ctx.addChunk(\", \");<br/>        ctx.addArgument(1);<br/>        ctx.addChunk(\")\");<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;Tuple&gt; fuzzySearch(String keyword) {<br/>    return cbf.create(em, Tuple.class)<br/>        .from(Product.class, \"p\")<br/>        .select(\"p.name\")<br/>        .select(\"p.price\")<br/>        .select(\"FUNCTION('pg_similarity', p.name, :keyword)\",<br/>                \"score\")<br/>        .where(\"FUNCTION('pg_similarity', p.name, :keyword)\")<br/>            .gt(0.3f)<br/>        .setParameter(\"keyword\", keyword)<br/>        .orderByDesc(\"FUNCTION('pg_similarity', p.name, :keyword)\")<br/>        .getResultList();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（需要 pg_trgm 扩展）:<br/>SELECT p.name, p.price, similarity(p.name, ?) AS score<br/>FROM products p<br/>WHERE similarity(p.name, ?) &gt; 0.3<br/>ORDER BY similarity(p.name, ?) DESC</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.7 JpqlMacro — 审计字段注入</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlMacro</code> 在查询<strong style=\"color:#1a1a2e;font-weight:700;\">构建阶段</strong>展开，将宏名称替换为 JPQL 表达式片段——适合注入\"当前用户\"、\"当前租户\"等运行时上下文。与 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 的区别在于：Macro 在 JPQL 解析前展开，Function 在 SQL 渲染时翻译。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-10 JpqlFunction vs JpqlMacro 生命周期对比</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">JPQL 解析器</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">SQL 渲染器</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 JpqlMacro — 解析阶段展开</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 JpqlFunction — 渲染阶段翻译</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">实现当前用户宏</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class CurrentUserMacro implements JpqlMacro {<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        String currentUser = SecurityContextHolder.getContext()<br/>            .getAuthentication().getName();<br/>        ctx.addChunk(\"'\" + currentUser + \"'\");<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">实现当前租户宏</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class CurrentTenantMacro implements JpqlMacro {<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        String tenantId = TenantContext.getCurrentTenantId();<br/>        ctx.addChunk(\"'\" + tenantId + \"'\");<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">注册宏</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Bean<br/>public CriteriaBuilderFactory cbf(EntityManagerFactory emf) {<br/>    CriteriaBuilderConfiguration config = Criteria.getDefault();<br/><br/>    config.registerMacro(\"CURRENT_USER_NAME\",<br/>                         new CurrentUserMacro());<br/>    config.registerMacro(\"CURRENT_TENANT\",<br/>                         new CurrentTenantMacro());<br/>    config.registerMacro(\"NOW\",<br/>                         ctx -&gt; ctx.addChunk(\"CURRENT_TIMESTAMP\"));<br/><br/>    config.registerFunction(<br/>        new JpqlFunctionGroup(\"pg_search\",<br/>                              new PgSearchFunction()));<br/><br/>    return config.createCriteriaBuilderFactory(emf);<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">在 Entity View 中使用宏</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@UpdatableEntityView<br/>@EntityView(Order.class)<br/>public interface OrderCreateView {<br/>    @IdMapping Long getId();<br/>    void setStatus(OrderStatus status);<br/>    void setTotalAmount(BigDecimal totalAmount);<br/><br/>    @Mapping(\"MACRO(CURRENT_USER_NAME)\")<br/>    String getCreatedBy();<br/><br/>    @Mapping(\"MACRO(CURRENT_TENANT)\")<br/>    String getTenantId();<br/><br/>    @Mapping(\"MACRO(NOW)\")<br/>    LocalDateTime getCreatedAt();<br/>}</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">维度</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">JpqlFunction</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">JpqlMacro</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">展开时机</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">SQL 渲染阶段</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">JPQL 解析阶段</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">接收参数</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ctx.addArgument(i)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ctx.addArgument(i)</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">输出类型</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">SQL 原生语法</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">JPQL 表达式片段</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">典型用途</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">数据库特有函数（全文搜索、JSON）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">运行时上下文注入（用户、租户）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">注册方式</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">registerFunction(JpqlFunctionGroup)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">registerMacro(name, JpqlMacro)</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">是否出现在 SQL</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">渲染为原生函数调用</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">展开为字面量或子表达式</td></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.8 Entity View 继承与多态</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当同一个实体根据状态需要展示不同字段时，Entity View 的继承机制可以做到<strong style=\"color:#1a1a2e;font-weight:700;\">按条件自动分派子 View</strong>——类似 Java 多态的思想。通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityViewInheritanceMapping</code> 注解定义匹配条件，运行时框架自动选择最匹配的子 View。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-11 Entity View 继承——按订单状态分派 View</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">OrderListView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;interface&gt;&gt; · Long getId · OrderStatus getStatus · BigDecimal getTotalAmount · String getCustomerName</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">PendingOrderView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;interface&gt;&gt; · Long getHoursSinceCreated · String getAssignedAgent</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">ShippedOrderView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;interface&gt;&gt; · String getTrackingNumber · LocalDate getEstimatedDelivery</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CompletedOrderView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;interface&gt;&gt; · LocalDateTime getCompletedAt · BigDecimal getFinalAmount</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">基类 View</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>@EntityViewInheritance<br/>public interface OrderListView {<br/>    @IdMapping Long getId();<br/>    OrderStatus getStatus();<br/>    BigDecimal getTotalAmount();<br/>    @Mapping(\"customer.name\") String getCustomerName();<br/>    LocalDateTime getCreatedAt();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">PENDING 状态子 View</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>@EntityViewInheritanceMapping(\"status = 'PENDING'\")<br/>public interface PendingOrderView extends OrderListView {<br/><br/>    @Mapping(\"FUNCTION('HOURS_BETWEEN', createdAt, \"<br/>           + \"CURRENT_TIMESTAMP)\")<br/>    Long getHoursSinceCreated();<br/><br/>    @Mapping(\"assignedAgent.name\")<br/>    String getAssignedAgent();<br/><br/>    default String getUrgencyLevel() {<br/>        long hours = getHoursSinceCreated();<br/>        if (hours &gt; 48) return \"CRITICAL\";<br/>        if (hours &gt; 24) return \"HIGH\";<br/>        if (hours &gt; 12) return \"MEDIUM\";<br/>        return \"LOW\";<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">SHIPPED 状态子 View</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>@EntityViewInheritanceMapping(\"status = 'SHIPPED'\")<br/>public interface ShippedOrderView extends OrderListView {<br/><br/>    @Mapping(\"shipment.trackingNumber\")<br/>    String getTrackingNumber();<br/><br/>    @Mapping(\"shipment.estimatedDelivery\")<br/>    LocalDate getEstimatedDelivery();<br/><br/>    @Mapping(\"shipment.carrier\")<br/>    String getCarrier();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">COMPLETED 状态子 View</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>@EntityViewInheritanceMapping(\"status = 'COMPLETED'\")<br/>public interface CompletedOrderView extends OrderListView {<br/><br/>    @Mapping(\"completedAt\")<br/>    LocalDateTime getCompletedAt();<br/><br/>    @Mapping(\"totalAmount - COALESCE(discountAmount, 0)\")<br/>    BigDecimal getFinalAmount();<br/><br/>    @Mapping(\"rating\")<br/>    Integer getCustomerRating();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">查询自动分派</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public List&lt;OrderListView&gt; getAllOrders() {<br/>    return evm.applySetting(<br/>        EntityViewSetting.create(OrderListView.class),<br/>        cbf.create(em, Order.class)<br/>    ).getResultList();<br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// 返回的列表中:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// status=PENDING 的元素 → PendingOrderView 实例</span><br/><span style=\"color:#6c7086;font-style:italic;\">// status=SHIPPED 的元素 → ShippedOrderView 实例</span><br/><span style=\"color:#6c7086;font-style:italic;\">// status=COMPLETED 的元素 → CompletedOrderView 实例</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 其他状态 → 基类 OrderListView 实例</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.9 Correlated Subquery in Entity View</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">在 Entity View 中通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelatedSimple</code> 声明关联子查询，可以为每个实体计算汇总统计字段——如\"该客户的总订单数\"、\"该商品的平均评分\"——而无需在 Service 层手动拼接。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">客户 View 带关联统计</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Customer.class)<br/>public interface CustomerDetailView {<br/>    @IdMapping Long getId();<br/>    String getName();<br/>    String getEmail();<br/><br/>    @MappingCorrelatedSimple(<br/>        correlated = Order.class,<br/>        correlationBasis = \"this\",<br/>        correlationExpression =<br/>            \"correlationKey = customer.id\",<br/>        correlationResult = \"COUNT(id)\"<br/>    )<br/>    Long getTotalOrders();<br/><br/>    @MappingCorrelatedSimple(<br/>        correlated = Order.class,<br/>        correlationBasis = \"this\",<br/>        correlationExpression =<br/>            \"correlationKey = customer.id\",<br/>        correlationResult = \"SUM(totalAmount)\"<br/>    )<br/>    BigDecimal getTotalSpent();<br/><br/>    @MappingCorrelatedSimple(<br/>        correlated = Order.class,<br/>        correlationBasis = \"this\",<br/>        correlationExpression =<br/>            \"correlationKey = customer.id\",<br/>        correlationResult = \"AVG(totalAmount)\"<br/>    )<br/>    BigDecimal getAvgOrderValue();<br/><br/>    @MappingCorrelatedSimple(<br/>        correlated = Order.class,<br/>        correlationBasis = \"this\",<br/>        correlationExpression =<br/>            \"correlationKey = customer.id\",<br/>        correlationResult = \"MAX(createdAt)\"<br/>    )<br/>    LocalDateTime getLastOrderDate();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（每个关联统计 → 一个 Correlated Subquery）:<br/>SELECT c.id, c.name, c.email,<br/>    (SELECT COUNT(o1.id)<br/>     FROM orders o1 WHERE o1.customer_id = c.id) AS total_orders,<br/>    (SELECT SUM(o2.total_amount)<br/>     FROM orders o2 WHERE o2.customer_id = c.id) AS total_spent,<br/>    (SELECT AVG(o3.total_amount)<br/>     FROM orders o3 WHERE o3.customer_id = c.id) AS avg_order_value,<br/>    (SELECT MAX(o4.created_at)<br/>     FROM orders o4 WHERE o4.customer_id = c.id) AS last_order_date<br/>FROM customers c<br/>WHERE c.id = ?</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-12 Correlated Subquery 与 @MappingCorrelatedSimple 映射</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">VIEW</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@MappingCorrelatedSimple<br/>correlated = Order.class</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">correlationExpression =<br/>'correlationKey = customer.id'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">correlationResult =<br/>'COUNT(id)' / 'SUM(totalAmount)'</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">RENDER</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">为每个关联字段生成<br/>Correlated Subquery</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WHERE o.customer_id = c.id<br/>↑ correlationExpression</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT COUNT(o.id)<br/>↑ correlationResult</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">SQL</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT c.id, c.name,<br/>(SELECT COUNT... FROM orders WHERE customer_id = c.id),<br/>(SELECT SUM...),<br/>(SELECT AVG...),<br/>(SELECT MAX...)</p></section></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">商品 View 带评分统计</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Product.class)<br/>public interface ProductDetailView {<br/>    @IdMapping Long getId();<br/>    String getName();<br/>    BigDecimal getPrice();<br/>    @Mapping(\"category.name\") String getCategoryName();<br/><br/>    @MappingCorrelatedSimple(<br/>        correlated = Review.class,<br/>        correlationBasis = \"this\",<br/>        correlationExpression =<br/>            \"correlationKey = product.id\",<br/>        correlationResult = \"AVG(rating)\"<br/>    )<br/>    Double getAverageRating();<br/><br/>    @MappingCorrelatedSimple(<br/>        correlated = Review.class,<br/>        correlationBasis = \"this\",<br/>        correlationExpression =<br/>            \"correlationKey = product.id\",<br/>        correlationResult = \"COUNT(id)\"<br/>    )<br/>    Long getReviewCount();<br/><br/>    @MappingCorrelatedSimple(<br/>        correlated = OrderItem.class,<br/>        correlationBasis = \"this\",<br/>        correlationExpression =<br/>            \"correlationKey = product.id\",<br/>        correlationResult = \"SUM(quantity)\"<br/>    )<br/>    Long getTotalSold();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">性能注意</strong>：每个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelatedSimple</code> 字段都会生成一个 Correlated Subquery。如果一个 View 有 5 个关联统计字段且查询返回 100 行，数据库需要执行 500 次子查询。对于列表场景，考虑将统计字段拆分到单独的 View（详情页使用），或改用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@BatchFetch</code> 策略减少数据库往返。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">使用 CorrelationProvider 自定义关联逻辑</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class RecentOrderCorrelationProvider<br/>        implements CorrelationProvider {<br/><br/>    @Override<br/>    public void applyCorrelation(<br/>            CorrelationBuilder correlationBuilder,<br/>            String correlationExpression) {<br/>        correlationBuilder<br/>            .correlate(Order.class)<br/>            .on(\"customer.id\")<br/>            .eqExpression(correlationExpression)<br/>            .on(\"createdAt\")<br/>            .geExpression(\"FUNCTION('DATE_SUB_DAYS', \"<br/>                        + \"CURRENT_TIMESTAMP, 30)\");<br/>    }<br/>}<br/><br/>@EntityView(Customer.class)<br/>public interface CustomerRecentActivityView {<br/>    @IdMapping Long getId();<br/>    String getName();<br/><br/>    @MappingCorrelated(<br/>        correlationBasis = \"id\",<br/>        correlationResult = \"COUNT(id)\",<br/>        correlator = RecentOrderCorrelationProvider.class<br/>    )<br/>    Long getRecentOrderCount();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（带时间范围过滤的关联子查询）:<br/>SELECT c.id, c.name,<br/>    (SELECT COUNT(o.id)<br/>     FROM orders o<br/>     WHERE o.customer_id = c.id<br/>       AND o.created_at &gt;= CURRENT_TIMESTAMP - INTERVAL '30 days')<br/>     AS recent_order_count<br/>FROM customers c</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-13 关联子查询策略选型决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">FK</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PK</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">需要关联统计字段</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 关联条件简单？<br/>只有 FK = PK</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@MappingCorrelatedSimple<br/>一行注解搞定</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要额外过滤条件？<br/>如时间范围、状态</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@MappingCorrelated<br/>+ CorrelationProvider</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 返回行数多？<br/>> 50 行</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">考虑 @BatchFetch<br/>或拆分 View</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 直接使用</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">23.10 陷阱与常见问题</h2></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 1：CTE 实体缺少 @Id</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 错误：CTE 实体没有 @Id → 运行时异常</span><br/>@CTE @Entity<br/>public class BrokenCTE {<br/>    String name;<br/>    BigDecimal total;<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 缺少 @Id！</span><br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// IllegalArgumentException: Entity type 'BrokenCTE'</span><br/><span style=\"color:#6c7086;font-style:italic;\">// does not have an id attribute</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：必须有 @Id</span><br/>@CTE @Entity<br/>public class CorrectCTE {<br/>    @Id Long id;  <span style=\"color:#6c7086;font-style:italic;\">// 即使 CTE 不需要主键概念，JPA 要求必须有</span><br/>    String name;<br/>    BigDecimal total;<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 2：CTE 实体未注册到 persistence.xml</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">&lt;!-- persistence.xml 中必须包含 CTE 实体 --&gt;<br/>&lt;persistence-unit name=\"default\"&gt;<br/>    &lt;class&gt;com.example.entity.Order&lt;/class&gt;<br/>    &lt;class&gt;com.example.entity.Customer&lt;/class&gt;<br/>    &lt;!-- ❌ 忘记注册 CTE 实体 → 查询时找不到 --&gt;<br/>    &lt;!-- ✅ 必须注册 --&gt;<br/>    &lt;class&gt;com.example.cte.MonthlySalesCTE&lt;/class&gt;<br/>    &lt;class&gt;com.example.cte.CategoryTreeCTE&lt;/class&gt;<br/>&lt;/persistence-unit&gt;<br/><br/>&lt;!-- Spring Boot 方案：用 @EntityScan 扫描 CTE 包 --&gt;</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@SpringBootApplication<br/>@EntityScan(basePackages = {<br/>    \"com.example.entity\",<br/>    \"com.example.cte\"  <span style=\"color:#6c7086;font-style:italic;\">// CTE 实体必须被扫描到</span><br/>})<br/>public class Application {<br/>    public static void main(String[] args) {<br/>        SpringApplication.run(Application.class, args);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 3：窗口函数 JPQL 语法与标准 SQL 差异</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 错误：直接用 SQL 语法写窗口函数</span><br/>cb.select(\"RANK() OVER (ORDER BY SUM(o.totalAmount) DESC)\");<br/><span style=\"color:#6c7086;font-style:italic;\">// Blaze-Persistence 无法解析！</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：用 WINDOW_ 前缀</span><br/>cb.select(\"WINDOW_RANK() OVER (\"<br/>        + \"ORDER BY SUM(o.totalAmount) DESC)\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 常用窗口函数前缀映射:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL RANK()       → WINDOW_RANK()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL DENSE_RANK() → WINDOW_DENSE_RANK()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL ROW_NUMBER() → WINDOW_ROW_NUMBER()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL SUM()        → WINDOW_SUM()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL LAG()        → WINDOW_LAG()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL LEAD()       → WINDOW_LEAD()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL FIRST_VALUE()→ WINDOW_FIRST_VALUE()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL LAST_VALUE() → WINDOW_LAST_VALUE()</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL NTILE()      → WINDOW_NTILE()</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 4：JpqlFunction vs JpqlMacro 混淆</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-14 JpqlFunction vs JpqlMacro 选择指南</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">需要自定义表达式</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要翻译为数据库<br/>特有 SQL 语法？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ JpqlFunction<br/>SQL 渲染阶段</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要注入运行时<br/>上下文？如用户/租户</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ JpqlMacro<br/>JPQL 解析阶段</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 只是简单别名？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">示例: pg_search,<br/>array_agg, similarity</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">示例: CURRENT_USER,<br/>CURRENT_TENANT, NOW</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 5：隐式 JOIN 性能问题</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 性能陷阱：多次引用隐式路径 → 多次 JOIN</span><br/>cb.select(\"o.customer.name\")<br/>  .select(\"o.customer.email\")<br/>  .select(\"o.customer.phone\")<br/>  .where(\"o.customer.status\").eq(\"ACTIVE\");<br/><span style=\"color:#6c7086;font-style:italic;\">// 某些 JPA 实现可能生成 4 次 JOIN customer 表！</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：显式 JOIN 一次</span><br/>cb.innerJoin(\"o.customer\", \"c\")<br/>  .select(\"c.name\")<br/>  .select(\"c.email\")<br/>  .select(\"c.phone\")<br/>  .where(\"c.status\").eq(\"ACTIVE\");<br/><span style=\"color:#6c7086;font-style:italic;\">// → 只有 1 次 JOIN</span></p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- ❌ 可能生成的低效 SQL:<br/>SELECT c1.name, c2.email, c3.phone<br/>FROM orders o<br/>JOIN customers c1 ON o.customer_id = c1.id<br/>JOIN customers c2 ON o.customer_id = c2.id<br/>JOIN customers c3 ON o.customer_id = c3.id<br/>WHERE c4.status = 'ACTIVE'<br/><br/>-- ✅ 正确的单次 JOIN:<br/>SELECT c.name, c.email, c.phone<br/>FROM orders o<br/>INNER JOIN customers c ON o.customer_id = c.id<br/>WHERE c.status = 'ACTIVE'</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 6：Entity View 继承映射条件顺序</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 陷阱：多个子 View 匹配条件重叠</span><br/>@EntityViewInheritanceMapping(\"status = 'PAID'\")<br/>public interface PaidOrderView extends OrderListView { ... }<br/><br/>@EntityViewInheritanceMapping(\"status = 'PAID' \"<br/>    + \"AND totalAmount &gt; 1000\")<br/>public interface HighValuePaidOrderView extends OrderListView { ... }<br/><span style=\"color:#6c7086;font-style:italic;\">// 如果订单 status=PAID 且 totalAmount=2000，</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 匹配到哪个 View 取决于注册顺序！</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：子 View 条件必须互斥</span><br/>@EntityViewInheritanceMapping(\"status = 'PAID' \"<br/>    + \"AND totalAmount &lt;= 1000\")<br/>public interface RegularPaidOrderView extends OrderListView { ... }<br/><br/>@EntityViewInheritanceMapping(\"status = 'PAID' \"<br/>    + \"AND totalAmount &gt; 1000\")<br/>public interface HighValuePaidOrderView extends OrderListView { ... }</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 7：聚合 View 缺少 GROUP BY 隐式行为</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ⚠️ 注意：Entity View 的聚合字段会自动推导 GROUP BY</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 但非聚合字段必须全部出现在 GROUP BY 中</span><br/><br/>@EntityView(Order.class)<br/>public interface BrokenAggView {<br/>    @Mapping(\"status\")<br/>    OrderStatus getStatus();        <span style=\"color:#6c7086;font-style:italic;\">// 非聚合 → GROUP BY</span><br/><br/>    @Mapping(\"customer.name\")<br/>    String getCustomerName();       <span style=\"color:#6c7086;font-style:italic;\">// 非聚合 → GROUP BY</span><br/><br/>    @Mapping(\"COUNT(id)\")<br/>    Long getOrderCount();           <span style=\"color:#6c7086;font-style:italic;\">// 聚合</span><br/><br/>    @Mapping(\"SUM(totalAmount)\")<br/>    BigDecimal getTotalRevenue();   <span style=\"color:#6c7086;font-style:italic;\">// 聚合</span><br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// → GROUP BY o.status, c.name</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 如果有 100 个客户 × 5 种状态 = 最多 500 行</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 确保这是你想要的粒度！</span></p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">陷阱</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">症状</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">解决方案</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">CTE 无 @Id</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">IllegalArgumentException</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">添加 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Id</code> 字段</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">CTE 未注册</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityType not found</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">加入 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityScan</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">窗口函数前缀</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">解析失败</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WINDOW_</code> 前缀</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Function/Macro 混淆</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">SQL 结果不符预期</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">按生命周期选择</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">隐式 JOIN 重复</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">SQL 多次 JOIN</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">显式 JOIN 别名</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">继承条件重叠</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">分派不确定</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">条件互斥</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">聚合 GROUP BY</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">结果粒度错误</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">检查非聚合字段</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 23-15 本章知识体系回顾</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">root((高级查询与[BR]自定义函数</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">动态查询</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">Specification</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">CriteriaBuilder</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">条件组合</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">聚合仪表盘</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">Entity View 聚合</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">Tuple 聚合</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">多维度交叉</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">窗口函数</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">RANK / DENSE_RANK</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">累计 SUM</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">LAG 环比</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">CTE</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">月度排名 Top N</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">递归分类树</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">带计数的树</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">扩展机制</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">JpqlFunction</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">JpqlMacro</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">注册流程</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">高级 View</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">继承多态</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">Correlated Subquery</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">CorrelationProvider</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">动态条件查询</strong>有两条路径：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Specification</code> 集成 Spring Data 分页排序、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code> 支持 CTE/窗口函数等高级表达式——按团队技术栈和查询复杂度选择</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">聚合 Entity View</strong> 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping(\"COUNT(id)\")</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SUM</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">AVG</code> 在接口层声明聚合逻辑——类型安全、可测试，一条 SQL 返回完整仪表盘数据</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">窗口函数</strong>在不改变行数的前提下计算排名（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WINDOW_RANK</code>）、累计（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WINDOW_SUM</code>）、环比（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WINDOW_LAG</code>）——单条 SQL 同时返回多个维度</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">CTE</strong> 将复杂查询分解为命名步骤——先计算排名，再过滤 Top N，可读性和性能兼优</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">递归 CTE</strong> 在一条 SQL 中展开任意深度的分类树——Anchor 定义根节点，UNION ALL 递归展开子节点，path 字段跟踪完整路径</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">JpqlFunction</strong> 在 SQL 渲染阶段将 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FUNCTION('pg_search', ...)</code> 翻译为 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">to_tsvector() @@ to_tsquery()</code>——集成数据库特有功能的标准方式</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">JpqlMacro</strong> 在 JPQL 解析阶段展开——<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">MACRO(CURRENT_USER_NAME)</code> 变为当前用户字面量，适合审计和多租户上下文注入</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Entity View 继承</strong>通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityViewInheritanceMapping</code> 按条件自动分派子 View——PENDING、SHIPPED、COMPLETED 各显示不同字段</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Correlated Subquery</strong> 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelatedSimple</code> 为每行计算关联统计——<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CorrelationProvider</code> 支持更复杂的关联条件</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">七大陷阱</strong>：CTE 需 @Id、CTE 需注册、窗口函数用 WINDOW_ 前缀、Function/Macro 按时机选、显式 JOIN 避免重复、继承条件需互斥、聚合字段影响 GROUP BY 粒度</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 <span style=\"color:#1e6fff;\">第 24 章 · 生产环境实战</span> 将把这些高级查询技术部署到真实生产环境——连接池调优、查询缓存策略、监控与告警、灰度发布，让 Blaze-Persistence 在高并发场景下稳定运行。</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 23 章</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}